tool_input.code:
import requests
import json

# Try with different sector values
url = "https://api.openei.org/utility_rates"
params = {
    "version": "latest",
    "format": "json",
    "detail": "full",
    "address": "Chicago, IL",
    "sector": "Commercial",  # Try capitalized
    "min_demand_kw": 500
}

try:
    response = requests.get(url, params=params, timeout=30)
    print(f"Status: {response.status_code}")
    if response.status_code == 200:
        data = response.json()
        print(json.dumps(data, indent=2)[:5000])
    else:
        print(f"Error: {response.text[:1000]}")
except Exception as e:
    print(f"Error: {e}")

# Try with sector=Commercial and different address format
print("\n--- Trying with different sector values ---")
for sector in ["Commercial", "Industrial", "commercial", "industrial", "Commercial/Industrial"]:
    params = {
        "version": "latest",
        "format": "json",
        "detail": "full",
        "address": "Chicago, IL",
        "sector": sector,
        "min_demand_kw": 500
    }
    try:
        response = requests.get(url, params=params, timeout=30)
        print(f"Sector '{sector}': Status {response.status_code}")
        if response.status_code == 200:
            data = response.json()
            if data.get('items'):
                print(f"  Found {len(data['items'])} items")
                print(json.dumps(data, indent=2)[:3000])
            else:
                print(f"  Items: {data.get('items', [])}")
                print(f"  Errors: {data.get('errors', [])}")
    except Exception as e:
        print(f"  Error: {e}")

